mcp:tool-listener.mcp:parameters-schema:
  {
  "inputSchema": {
    "type": "object",
    "properties": {
      "query": {
        "type": "string",
        "description": "Search query such as API name, flow name, or business keyword (example: invoice-sys-api, order processing)"
      },
      "spaceKey": {
        "type": "string",
        "description": "Confluence space key where API documentation is stored"
      }
    },
    "required": ["query"]
  }
}

set-variable.value:
#[var q = lower(payload.question)
// Detect shift-type question by keywords or time pattern
var isShiftQuestion = (q contains 'shift') or (q contains 'rota') or (q contains 'on call') or (q contains 'schedule') or (q matches (/.*\d{1,2}\s*(am|pm|:00).*/))
// For shift questions use 'rota' as the search keyword
// so Confluence finds the rota/schedule page directly
var keyword =
                        if ( isShiftQuestion ) 'rota'
                        else do {
	var stopWords = ['what','is','the','are','who','how','where',
                                             'when','does','do','a','an','of','in','for',
                                             'their','his','her','its','our','your','role',
                                             'tell','me','about','shift','on']
	var words = (q replace /[^a-z0-9 ]/ with '') splitBy ' '
	var kws   = words filter ((w) -> sizeOf(w) > 2 and !(stopWords contains w))
	---
	if ( isEmpty(kws) ) payload.question else kws[0]
}
---
{
	isShiftQuestion: isShiftQuestion,
	keyword: keyword
}]

set-payload.value:
#[output application/json --- {
                        answer      : "No Confluence pages were found containing information relevant to your question.",
                        source_page : null,
                        source_url  : null
                    }]
